      'explanatory_8mark': [
        {'question': '"কোড নেপোলিয়ান ছিল বিপ্লবী আদর্শ ও পুরোনো ঐতিহ্যের সমন্বয়" — ব্যাখ্যা করো।', 'answer': 'কোড নেপোলিয়ান ছিল নেপোলিয়ানের আইন সংস্কারের সর্বশ্রেষ্ঠ কীর্তি। এটি ছিল বিপ্লবী আদর্শ ও পুরোনো ঐতিহ্যের এক অনন্য সমন্বয়। একদিকে এতে ফরাসি বিপ্লবের মূল আদর্শগুলি স্থান পেয়েছিল — আইনের চোখে সকলের সমতা, ধর্মীয় সহিষ্ণুতা, উত্তরাধিকারে সমানাধিকার, সামন্ততান্ত্রিক বিশেষ সুবিধার উচ্ছেদ, প্রতিভার স্বাভাবিক স্ফুরণের সুযোগ। এই দিক থেকে এটি ছিল বিপ্লবের ফসল সংরক্ষণের একটি প্রয়াস। অন্যদিকে এতে পুরোনো রাজতান্ত্রিক ঐতিহ্যের ছাপও স্পষ্ট। নেপোলিয়ান নিজেই বলেছিলেন, তিনি বিপ্লবের সন্তান এবং বিপ্লবের ধ্বংসকারী উভয়ই। এই দ্বৈত চরিত্র কোড নেপোলিয়ানে প্রতিফলিত হয়। এতে নারীকে পুরুষের অধীনে রাখা হয়, বিবাহবিচ্ছেদের অধিকার সংকুচিত হয়, শ্রমিকদের ট্রেড ইউনিয়ন গঠনের অধিকার দেওয়া হয়নি। ব্যক্তি স্বাধীনতা ও মত প্রকাশের স্বাধীনতা এতে সীমিত ছিল। অর্থাৎ বিপ্লবের স্বাধীনতার আদর্শ এতে পূর্ণতা পায়নি।। সমগ্র ফ্রান্সে একইরকম আইন প্রবর্তিত হওয়ায় দেশবাসীর মধ্যে ঐক্য গড়ে ওঠে — যা বিপ্লবের \'মৈত্রী\' আদর্শের প্রতিফলন। আবার কেন্দ্রীভূত শাসন ও নেপোলিয়ানের কর্তৃত্ব দৃঢ় হওয়ায় প্রগতিশীল পরিবর্তনের পথ বন্ধ হয়ে যায়। লেফেভর এই আইনবিধিকে \'ফরাসি সমাজের বাইবেল\' বলে প্রশংসা করেন। নেপোলিয়ান ইটালি, জার্মানির রাজ্যগুলিতে কোড নেপোলিয়ান চালু করেছিলেন, যা ওই দেশগুলির ঐক্যের ও স্বাধীন রাষ্ট্র হিসেবে গড়ে ওঠার ক্ষেত্রে সহায়ক হয়েছিল। বেলজিয়াম ও লুক্সেমবার্গে এই আইনবিধি এখনও প্রচলিত আছে। এই আইনের জন্য নেপোলিয়ানকে \'দ্বিতীয় জাস্টিনিয়ান\' বলা হয়। সুতরাং কোড নেপোলিয়ান ছিল বিপ্লবী আদর্শ ও পুরোনো ঐতিহ্যের এক জটিল কিন্তু ফলপ্রসূ সমন্বয়।'},
        {'question': '"কোড নেপোলিয়ান আইনের চোখে সাম্য প্রতিষ্ঠা করলেও নারীর অধিকার সীমিত করে" — বিশ্লেষণ করো।', 'answer': 'কোড নেপোলিয়ান আইনের চোখে সকল নাগরিকের সমতার নীতি প্রতিষ্ঠা করলেও নারীর অধিকারের ক্ষেত্রে তা ছিল বৈষম্যমূলক। আইনের দৃষ্টিতে সমতা: কোড নেপোলিয়ানের দেওয়ানি আইনে সকল ব্যক্তি আইনের চোখে সমান — এই নীতি ঘোষিত হয়। সামন্ততান্ত্রিক বিশেষ সুবিধার উচ্ছেদ, যোগ্যতার ভিত্তিতে সরকারি চাকরির সুযোগ ও সম্পত্তির অধিকার সকল নাগরিকের জন্য উন্মুক্ত হয়। ধর্মীয় সহিষ্ণুতা ও উত্তরাধিকার ক্ষেত্রে সমানাধিকার প্রতিষ্ঠিত হয়। নারীর অধিকার সীমিতকরণ: কিন্তু এই সাধারণ সমতার নীতি নারীর ক্ষেত্রে প্রযোজ্য হয়নি। কোড নেপোলিয়ানে নারীকে পুরুষের অধীনে রাখা হয় এবং নারীর মর্যাদা হ্রাস করা হয়। পারিবারিক সম্পত্তির অধিকার থেকে নারীদের বঞ্চিত করা হয়। বিবাহ বিচ্ছেদের অধিকার সংকুচিত করা হয়। নারীরা স্বামীর অনুগত থাকতে বাধ্য ছিল এবং স্বামীর সম্পত্তি ও সন্তানের ওপর কর্তৃত্ব ছিল। এই বৈষম্যের কারণ: নেপোলিয়ান নারীকে পুরুষের অধীনস্থ মনে করতেন এবং পারিবারিক স্থিতিশীলতার জন্য পুরুষের কর্তৃত্ব প্রয়োজন বলে বিশ্বাস করতেন। তিনি বিপ্লবের সময়ে নারীদের রাজনৈতিক সক্রিয়তা দেখে শঙ্কিত ছিলেন এবং নারীদের গৃহস্থালির কাজে সীমাবদ্ধ রাখতে চেয়েছিলেন। সুতরাং কোড নেপোলিয়ান আইনের চোখে সাম্য প্রতিষ্ঠা করলেও নারীর অধিকারের ক্ষেত্রে বিপ্লবের আদর্শ থেকে সরে গিয়ে পুরোনো পিতৃতান্ত্রিক ঐতিহ্য বহাল রাখে।'},
